INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Incline_Push-Up_Reverse_Grip','Incline Push-Up Reverse Grip','pecho',ARRAY['abdominales','hombros','tríceps'],'peso corporal','strength',ARRAY['Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.','Place your hands on the bar palms up, with your hands about shoulder width apart.','Position your feet back from the bar with arms and body straight. This will be your starting position.','Keeping your body straight, lower your chest to the bar by bending the arms.','Return to the starting position by extending the elbows, pressing yourself back up.'],'Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height. Place your hands on the bar palms up, with your hands about shoulder width apart. Position your feet back from the bar with arms and body straight. This will be your starting position. Keeping your body straight, lower your chest to the bar by bending the arms. Return to the starting position by extending the elbows, pressing yourself back up.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Reverse_Grip/0.jpg','exercisedb',true),('Incline_Push-Up_Wide','Incline Push-Up Wide','pecho',ARRAY['abdominales','hombros','tríceps'],'peso corporal','strength',ARRAY['Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.','Place your hands on the bar, with your hands wider than shoulder width.','Position your feet back from the bar with arms and body straight. Your arms should be perpendicular to the body. This will be your starting position.','Keeping your body straight, lower your chest to the bar by bending the arms.','Return to the starting position by extending the elbows, pressing yourself back up.'],'Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height. Place your hands on the bar, with your hands wider than shoulder width. Position your feet back from the bar with arms and body straight. Your arms should be perpendicular to the body. This will be your starting position. Keeping your body straight, lower your chest to the bar by bending the arms. Return to the starting position by extending the elbows, pressing yourself back up.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Wide/0.jpg','exercisedb',true),('Intermediate_Groin_Stretch','Intermediate Groin Stretch','isquiotibiales',ARRAY[],'otro','stretching',ARRAY['Lie on your back with your legs extended. Loop a belt, rope, or band around one of your feet, and swing that leg as far to the side as you can. This will be your starting position.','Pull gently on the belt to create tension in your groin and hamstring muscles. Hold for 10-20 seconds, and repeat on the other side.'],'Lie on your back with your legs extended. Loop a belt, rope, or band around one of your feet, and swing that leg as far to the side as you can. This will be your starting position. Pull gently on the belt to create tension in your groin and hamstring muscles. Hold for 10-20 seconds, and repeat on the other side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Groin_Stretch/0.jpg','exercisedb',true),('Intermediate_Hip_Flexor_and_Quad_Stretch','Intermediate Hip Flexor and Quad Stretch','cuádriceps',ARRAY[],'otro','stretching',ARRAY['Lie face down on the floor, with a rope, belt, or band looped around one foot.','Flex the knee and extend the hip of the leg to be stretched, using both hands to pull on the belt. Your knee and your hip should come off of the floor, creating tension in the hip flexors and quadriceps. Hold the stretch for 10-20 seconds, and repeat on the other leg.'],'Lie face down on the floor, with a rope, belt, or band looped around one foot. Flex the knee and extend the hip of the leg to be stretched, using both hands to pull on the belt. Your knee and your hip should come off of the floor, creating tension in the hip flexors and quadriceps. Hold the stretch for 10-20 seconds, and repeat on the other leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Hip_Flexor_and_Quad_Stretch/0.jpg','exercisedb',true),('Internal_Rotation_with_Band','Internal Rotation with Band','hombros',ARRAY[],'bandas elásticas','strength',ARRAY['Choke the band around a post. The band should be at the same height as your elbow. Stand with your right side to the band a couple of feet away.','Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.','With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching away from your torso. This will be your starting position.','Execute the movement by rotating your arm in a forehand motion, keeping your elbow in place.','Continue as far as you are able, pause, and then return to the starting position.'],'Choke the band around a post. The band should be at the same height as your elbow. Stand with your right side to the band a couple of feet away. Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position. With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching away from your torso. This will be your starting position. Execute the movement by rotating your arm in a forehand motion, keeping your elbow in place. Continue as far as you are able, pause, and then return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Internal_Rotation_with_Band/0.jpg','exercisedb',true),('Inverted_Row','Inverted Row','espalda media',ARRAY['dorsales'],NULL,'strength',ARRAY['Position a bar in a rack to about waist height. You can also use a smith machine.','Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.','Begin by flexing the elbow, pulling your chest towards the bar. Retract your shoulder blades as you perform the movement.','Pause at the top of the motion, and return yourself to the start position.','Repeat for the desired number of repetitions.'],'Position a bar in a rack to about waist height. You can also use a smith machine. Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position. Begin by flexing the elbow, pulling your chest towards the bar. Retract your shoulder blades as you perform the movement. Pause at the top of the motion, and return yourself to the start position. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row/0.jpg','exercisedb',true),('Inverted_Row_with_Straps','Inverted Row with Straps','espalda media',ARRAY['bíceps','dorsales'],'otro','strength',ARRAY['Hang a rope or suspension straps from a rack or other stable object. Grasp the ends and position yourself in a supine position hanging from the ropes. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.','Begin by flexing the elbow, pulling your chest to your hands. Retract your shoulder blades as you perform the movement.','Pause at the top of the motion, and return yourself to the start position.','Repeat for the desired number of repetitions.'],'Hang a rope or suspension straps from a rack or other stable object. Grasp the ends and position yourself in a supine position hanging from the ropes. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position. Begin by flexing the elbow, pulling your chest to your hands. Retract your shoulder blades as you perform the movement. Pause at the top of the motion, and return yourself to the start position. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row_with_Straps/0.jpg','exercisedb',true),('Iron_Cross','Iron Cross','hombros',ARRAY['pecho','glúteos','isquiotibiales','espalda baja','cuádriceps','trapecios'],'mancuernas','strength',ARRAY[],NULL,'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Cross/0.jpg','exercisedb',true),('Iron_Crosses_stretch','Iron Crosses (stretch)','cuádriceps',ARRAY[],NULL,'stretching',ARRAY['Lie face down on the floor, with your arms extended out to your side, palms pressed to the floor. This will be your starting position.','To begin, flex one knee and bring that leg across the back of your body, attempting to touch it to the ground near the opposite hand.','Promptly return the leg to the starting postion, and quickly repeat with the other leg. Continue alternating for 10-20 repetitions.'],'Lie face down on the floor, with your arms extended out to your side, palms pressed to the floor. This will be your starting position. To begin, flex one knee and bring that leg across the back of your body, attempting to touch it to the ground near the opposite hand. Promptly return the leg to the starting postion, and quickly repeat with the other leg. Continue alternating for 10-20 repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Crosses_stretch/0.jpg','exercisedb',true),('Isometric_Chest_Squeezes','Isometric Chest Squeezes','pecho',ARRAY['hombros','tríceps'],'peso corporal','plyometrics',ARRAY['While either seating or standing, bend your arms at a 90-degree angle and place the palms of your hands together in front of your chest. Tip: Your hands should be open with the palms together and fingers facing forward (perpendicular to your torso).','Push both hands against each other as you contract your chest. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.','Hold for the recommended number of seconds.','Now release the tension slowly.','Rest for the recommended amount of time and repeat.'],'While either seating or standing, bend your arms at a 90-degree angle and place the palms of your hands together in front of your chest. Tip: Your hands should be open with the palms together and fingers facing forward (perpendicular to your torso). Push both hands against each other as you contract your chest. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction. Hold for the recommended number of seconds. Now release the tension slowly. Rest for the recommended amount of time and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Chest_Squeezes/0.jpg','exercisedb',true),('Isometric_Neck_Exercise_-_Front_And_Back','Isometric Neck Exercise - Front And Back','cuello',ARRAY[],'peso corporal','strength',ARRAY['With your head and neck in a neutral position (normal position with head erect facing forward), place both of your hands on the front side of your head.','Now gently push forward as you contract the neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.','Hold for the recommended number of seconds.','Now release the tension slowly.','Rest for the recommended amount of time and repeat with your hands placed on the back side of your head.'],'With your head and neck in a neutral position (normal position with head erect facing forward), place both of your hands on the front side of your head. Now gently push forward as you contract the neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction. Hold for the recommended number of seconds. Now release the tension slowly. Rest for the recommended amount of time and repeat with your hands placed on the back side of your head.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Neck_Exercise_-_Front_And_Back/0.jpg','exercisedb',true),('Isometric_Neck_Exercise_-_Sides','Isometric Neck Exercise - Sides','cuello',ARRAY[],'peso corporal','strength',ARRAY['With your head and neck in a neutral position (normal position with head erect facing forward), place your left hand on the left side of your head.','Now gently push towards the left as you contract the left neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.','Hold for the recommended number of seconds.','Now release the tension slowly.','Rest for the recommended amount of time and repeat with your right hand placed on the right side of your head.'],'With your head and neck in a neutral position (normal position with head erect facing forward), place your left hand on the left side of your head. Now gently push towards the left as you contract the left neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction. Hold for the recommended number of seconds. Now release the tension slowly. Rest for the recommended amount of time and repeat with your right hand placed on the right side of your head.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Neck_Exercise_-_Sides/0.jpg','exercisedb',true),('Isometric_Wipers','Isometric Wipers','pecho',ARRAY['abdominales','hombros','tríceps'],'peso corporal','strength',ARRAY['Assume a push-up position, supporting your weight on your hands and toes while keeping your body straight. Your hands should be just outside of shoulder width. This will be your starting position.','Begin by shifting your body weight as far to one side as possible, allowing the elbow on that side to flex as you lower your body.','Reverse the motion by extending the flexed arm, pushing yourself up and then dropping to the other side.','Repeat for the desired number of repetitions.'],'Assume a push-up position, supporting your weight on your hands and toes while keeping your body straight. Your hands should be just outside of shoulder width. This will be your starting position. Begin by shifting your body weight as far to one side as possible, allowing the elbow on that side to flex as you lower your body. Reverse the motion by extending the flexed arm, pushing yourself up and then dropping to the other side. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Wipers/0.jpg','exercisedb',true),('JM_Press','JM Press','tríceps',ARRAY['pecho','hombros'],'barra','strength',ARRAY['Start the exercise the same way you would a close grip bench press. You will lie on a flat bench while holding a barbell at arms length (fully extended) with the elbows in. However, instead of having the arms perpendicular to the torso, make sure the bar is set in a direct line above the upper chest. This will be your starting position.','Now beginning from a fully extended position lower the bar down as if performing a lying triceps extension. Inhale as you perform this movement. When you reach the half way point, let the bar roll back about one inch by moving the upper arms towards your legs until they are perpendicular to the torso. Tip: Keep the bend at the elbows constant as you bring the upper arms forward.','As you exhale, press the bar back up by using the triceps to perform a close grip bench press.','Now go back to the starting position and start over.','Repeat for the recommended amount of repetitions.'],'Start the exercise the same way you would a close grip bench press. You will lie on a flat bench while holding a barbell at arms length (fully extended) with the elbows in. However, instead of having the arms perpendicular to the torso, make sure the bar is set in a direct line above the upper chest. This will be your starting position. Now beginning from a fully extended position lower the bar down as if performing a lying triceps extension. Inhale as you perform this movement. When you reach the half way point, let the bar roll back about one inch by moving the upper arms towards your legs until they are perpendicular to the torso. Tip: Keep the bend at the elbows constant as you bring the upper arms forward. As you exhale, press the bar back up by using the triceps to perform a close grip bench press. Now go back to the starting position and start over. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/JM_Press/0.jpg','exercisedb',true),('Jackknife_Sit-Up','Jackknife Sit-Up','abdominales',ARRAY[],'peso corporal','strength',ARRAY['Lie flat on the floor (or exercise mat) on your back with your arms extended straight back behind your head and your legs extended also. This will be your starting position.','As you exhale, bend at the waist while simultaneously raising your legs and arms to meet in a jackknife position. Tip: The legs should be extended and lifted at approximately a 35-45 degree angle from the floor and the arms should be extended and parallel to your legs. The upper torso should be off the floor.','While inhaling, lower your arms and legs back to the starting position.','Repeat for the recommended amount of repetitions.'],'Lie flat on the floor (or exercise mat) on your back with your arms extended straight back behind your head and your legs extended also. This will be your starting position. As you exhale, bend at the waist while simultaneously raising your legs and arms to meet in a jackknife position. Tip: The legs should be extended and lifted at approximately a 35-45 degree angle from the floor and the arms should be extended and parallel to your legs. The upper torso should be off the floor. While inhaling, lower your arms and legs back to the starting position. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jackknife_Sit-Up/0.jpg','exercisedb',true),('Janda_Sit-Up','Janda Sit-Up','abdominales',ARRAY[],'peso corporal','strength',ARRAY['Position your body on the floor in the basic sit-up position; knees to a ninety degree angle with feet flat on the floor and arms either crossed over your chest or to the sides. This will be your starting position.','As you strongly tighten your glutes and hamstrings, fill your lungs with air and in a slow (three to six second count) ascent, slowly exhale. Tip: It is important to tighten the glutes and hamstrings as this will cause the hip flexors to be inactivated in a process called reciprocal inhibition, which basically means that opposite muscles to the contracted ones will relax.','As you inhale, slowly go back in a controlled manner to the starting position.','Repeat for the recommended amount of repetitions.'],'Position your body on the floor in the basic sit-up position; knees to a ninety degree angle with feet flat on the floor and arms either crossed over your chest or to the sides. This will be your starting position. As you strongly tighten your glutes and hamstrings, fill your lungs with air and in a slow (three to six second count) ascent, slowly exhale. Tip: It is important to tighten the glutes and hamstrings as this will cause the hip flexors to be inactivated in a process called reciprocal inhibition, which basically means that opposite muscles to the contracted ones will relax. As you inhale, slowly go back in a controlled manner to the starting position. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Janda_Sit-Up/0.jpg','exercisedb',true),('Jefferson_Squats','Jefferson Squats','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales','espalda baja','trapecios'],'barra','strength',ARRAY['Place a barbell on the floor.','Stand in the middle of the bar length wise.','Bend down by bending at the knees and keeping your back straight and grasp the front of the bar with your right hand. Your palm should be in (neutral grip) facing the left side.','Grasp the rear of the bar with your left hand. The palm of your hand should be in neutral grip alignment (palms facing the right side). Tip: Ensure that your grip is even on the bar. Your torso should be positioned right in the middle of the bar and the distance between your torso and your right hand (which should be at the front) should be the same as the distance between your torso and your left hand (which should be to your back).','Now stand straight up with the weight. Tip: Your feet should be shoulder width apart and your toes slightly pointed out.','Squat down by bending at the knees and keeping your back straight until your upper thighs are parallel with the floor. Tip: Keep your back as vertical as possible with the floor and your head up. Also remember to not let your knees go past your toes. Inhale during this portion of the movement.','Now drive yourself back up to the starting position by pushing with the feet . Tip: Keep the bar hanging at arm''''s length and your elbows locked with a slight bend. The arms only serve as hooks. Avoid doing any lifting with them. Do the lifting with your thighs; not your arms.'],'Place a barbell on the floor. Stand in the middle of the bar length wise. Bend down by bending at the knees and keeping your back straight and grasp the front of the bar with your right hand. Your palm should be in (neutral grip) facing the left side. Grasp the rear of the bar with your left hand. The palm of your hand should be in neutral grip alignment (palms facing the right side). Tip: Ensure that your grip is even on the bar. Your torso should be positioned right in the middle of the bar and the distance between your torso and your right hand (which should be at the front) should be the same as the distance between your torso and your left hand (which should be to your back). Now stand straight up with the weight. Tip: Your feet should be shoulder width apart and your toes slightly pointed out. Squat down by bending at the knees and keeping your back straight until your upper thighs are parallel with the floor. Tip: Keep your back as vertical as possible with the floor and your head up. Also remember to not let your knees go past your toes. Inhale during this portion of the movement. Now drive yourself back up to the starting position by pushing with the feet . Tip: Keep the bar hanging at arm''s length and your elbows locked with a slight bend. The arms only serve as hooks. Avoid doing any lifting with them. Do the lifting with your thighs; not your arms.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jefferson_Squats/0.jpg','exercisedb',true),('Jerk_Balance','Jerk Balance','hombros',ARRAY['glúteos','isquiotibiales','cuádriceps','tríceps'],'barra','olympic weightlifting',ARRAY['This drill helps you learn to drive yourself low enough during the jerk and corrects those who move backward during the movement. Begin with the bar racked in the jerk position, with the shoulders forward, torso upright, and the feet split slightly apart.','Initiate the movement as you would a normal jerk, dipping at the knees while keeping your torso vertical, and driving back up forcefully, using momentum and not your arms to elevate the weight.','Keep the rear foot in place, using it to drive your body forward into a full split as you jerk the weight. Recover by standing up with the weight overhead.'],'This drill helps you learn to drive yourself low enough during the jerk and corrects those who move backward during the movement. Begin with the bar racked in the jerk position, with the shoulders forward, torso upright, and the feet split slightly apart. Initiate the movement as you would a normal jerk, dipping at the knees while keeping your torso vertical, and driving back up forcefully, using momentum and not your arms to elevate the weight. Keep the rear foot in place, using it to drive your body forward into a full split as you jerk the weight. Recover by standing up with the weight overhead.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jerk_Balance/0.jpg','exercisedb',true),('Jerk_Dip_Squat','Jerk Dip Squat','cuádriceps',ARRAY['abdominales','pantorrillas'],'barra','olympic weightlifting',ARRAY['This movement strengthens the dip portion of the jerk. Begin with the bar racked in the jerk position, with the shoulders forward to create a shelf and the bar lightly contacting the throat. The feet should be directly under the hips, with the feet turned out as is comfortable.','Keeping the torso vertical, dip by flexing the knees, allowing them to travel forward and without moving the hips to the rear. The dip should not be excessive. Return the weight to the starting position by driving forcefully though the feet.'],'This movement strengthens the dip portion of the jerk. Begin with the bar racked in the jerk position, with the shoulders forward to create a shelf and the bar lightly contacting the throat. The feet should be directly under the hips, with the feet turned out as is comfortable. Keeping the torso vertical, dip by flexing the knees, allowing them to travel forward and without moving the hips to the rear. The dip should not be excessive. Return the weight to the starting position by driving forcefully though the feet.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jerk_Dip_Squat/0.jpg','exercisedb',true),('Jogging_Treadmill','Jogging, Treadmill','cuádriceps',ARRAY['glúteos','isquiotibiales'],'máquina','cardio',ARRAY['To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.','Treadmills offer convenience, cardiovascular benefits, and usually have less impact than jogging outside. A 150 lb person will burn almost 250 calories jogging for 30 minutes, compared to more than 450 calories running. Maintain proper posture as you jog, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.'],'To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout. Treadmills offer convenience, cardiovascular benefits, and usually have less impact than jogging outside. A 150 lb person will burn almost 250 calories jogging for 30 minutes, compared to more than 450 calories running. Maintain proper posture as you jog, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jogging_Treadmill/0.jpg','exercisedb',true),('Keg_Load','Keg Load','espalda baja',ARRAY['abdominales','bíceps','pantorrillas','antebrazos','glúteos','isquiotibiales','espalda media','cuádriceps','hombros','trapecios'],'otro','strongman',ARRAY['To load kegs, place the desired number a distance from the loading platform, typically 30-50 feet.','Begin by grabbing the close handle of the first keg, tilting it onto its side to grab the opposite edge of the bottom of the keg. Lift the keg up to your chest.','The higher you can place the keg, the faster you should be able to move to the platform. Shouldering is usually not allowed. Be sure to keep a firm hold on the keg. Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible.','Return to the starting position to retrieve the next keg, and repeat until the event is completed.'],'To load kegs, place the desired number a distance from the loading platform, typically 30-50 feet. Begin by grabbing the close handle of the first keg, tilting it onto its side to grab the opposite edge of the bottom of the keg. Lift the keg up to your chest. The higher you can place the keg, the faster you should be able to move to the platform. Shouldering is usually not allowed. Be sure to keep a firm hold on the keg. Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible. Return to the starting position to retrieve the next keg, and repeat until the event is completed.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Keg_Load/0.jpg','exercisedb',true),('Kettlebell_Arnold_Press','Kettlebell Arnold Press','hombros',ARRAY['tríceps'],'kettlebells','strength',ARRAY['Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you raise the kettlebell towards your shoulder. The palm should be facing inward.','Looking straight ahead, press the kettlebell out and overhead, rotating your wrist so that your palm faces forward at the top of the motion.','Return the kettlebell to the starting position, with the palm facing in.'],'Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you raise the kettlebell towards your shoulder. The palm should be facing inward. Looking straight ahead, press the kettlebell out and overhead, rotating your wrist so that your palm faces forward at the top of the motion. Return the kettlebell to the starting position, with the palm facing in.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Arnold_Press/0.jpg','exercisedb',true),('Kettlebell_Dead_Clean','Kettlebell Dead Clean','isquiotibiales',ARRAY['pantorrillas','glúteos','espalda baja','cuádriceps','trapecios'],'kettlebells','strength',ARRAY['Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean the kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.','Lower the kettlebell, keeping the hamstrings loaded by keeping your back straight and your butt out.'],'Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead. Clean the kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so. Lower the kettlebell, keeping the hamstrings loaded by keeping your back straight and your butt out.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Dead_Clean/0.jpg','exercisedb',true),('Kettlebell_Figure_8','Kettlebell Figure 8','abdominales',ARRAY['isquiotibiales','hombros'],'kettlebells','strength',ARRAY['Place one kettlebell between your legs and take a wider than shoulder width stance. Bend over by pushing your butt out and keeping your back flat.','Pick up a kettlebell and pass it to your other hand between your legs. The receiving hand should reach from behind the legs. Go back and forth for several repetitions.'],'Place one kettlebell between your legs and take a wider than shoulder width stance. Bend over by pushing your butt out and keeping your back flat. Pick up a kettlebell and pass it to your other hand between your legs. The receiving hand should reach from behind the legs. Go back and forth for several repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Figure_8/0.jpg','exercisedb',true),('Kettlebell_Hang_Clean','Kettlebell Hang Clean','isquiotibiales',ARRAY['pantorrillas','glúteos','espalda baja','hombros','trapecios'],'kettlebells','strength',ARRAY['Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.','Lower kettlebell to a hanging position between your legs while keeping the hamstrings loaded. Keep your head up at all times.'],'Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead. Clean kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so. Lower kettlebell to a hanging position between your legs while keeping the hamstrings loaded. Keep your head up at all times.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Hang_Clean/0.jpg','exercisedb',true),('Kettlebell_One-Legged_Deadlift','Kettlebell One-Legged Deadlift','isquiotibiales',ARRAY['glúteos','espalda baja'],'kettlebells','strength',ARRAY['Hold a kettlebell by the handle in one hand. Stand on one leg, on the same side that you hold the kettlebell.','Keeping that knee slightly bent, perform a stiff legged deadlift by bending at the hip, extending your free leg behind you for balance.','Continue lowering the kettlebell until you are parallel to the ground, and then return to the upright position.'],'Hold a kettlebell by the handle in one hand. Stand on one leg, on the same side that you hold the kettlebell. Keeping that knee slightly bent, perform a stiff legged deadlift by bending at the hip, extending your free leg behind you for balance. Continue lowering the kettlebell until you are parallel to the ground, and then return to the upright position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_One-Legged_Deadlift/0.jpg','exercisedb',true),('Kettlebell_Pass_Between_The_Legs','Kettlebell Pass Between The Legs','abdominales',ARRAY['glúteos','isquiotibiales','hombros'],'kettlebells','strength',ARRAY['Place one kettlebell between your legs and take a comfortable stance. Bend over by pushing your butt out and keeping your back flat.','Pick up a kettlebell and pass it to your other hand between your legs, in the fashion of a "W". Go back and forth for several repetitions.'],'Place one kettlebell between your legs and take a comfortable stance. Bend over by pushing your butt out and keeping your back flat. Pick up a kettlebell and pass it to your other hand between your legs, in the fashion of a "W". Go back and forth for several repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pass_Between_The_Legs/0.jpg','exercisedb',true),('Kettlebell_Pirate_Ships','Kettlebell Pirate Ships','hombros',ARRAY['abdominales'],'kettlebells','strength',ARRAY['With a wide stance, hold a kettlebell with both hands. Allow it to hang at waist level with your arms extended. This will be your starting position.','Initiate the movement by turning to one side, swinging the kettlebell to head height. Briefly pause at the top of the motion.','Allow the bell to drop as you rotate to the opposite side, again raising the kettlebell to head height.','Repeat for the desired amount of repetitions.'],'With a wide stance, hold a kettlebell with both hands. Allow it to hang at waist level with your arms extended. This will be your starting position. Initiate the movement by turning to one side, swinging the kettlebell to head height. Briefly pause at the top of the motion. Allow the bell to drop as you rotate to the opposite side, again raising the kettlebell to head height. Repeat for the desired amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pirate_Ships/0.jpg','exercisedb',true),('Kettlebell_Pistol_Squat','Kettlebell Pistol Squat','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales','hombros'],'kettlebells','strength',ARRAY['Pick up a kettlebell with two hands and hold it by the horns. Hold one leg off of the floor and squat down on the other.','Squat down by flexing the knee and sitting back with the hips, holding the kettlebell up in front of you.','Hold the bottom position for a second and then reverse the motion, driving through the heel and keeping your head and chest up.','Lower yourself again and repeat.'],'Pick up a kettlebell with two hands and hold it by the horns. Hold one leg off of the floor and squat down on the other. Squat down by flexing the knee and sitting back with the hips, holding the kettlebell up in front of you. Hold the bottom position for a second and then reverse the motion, driving through the heel and keeping your head and chest up. Lower yourself again and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pistol_Squat/0.jpg','exercisedb',true),('Kettlebell_Seated_Press','Kettlebell Seated Press','hombros',ARRAY['tríceps'],'kettlebells','strength',ARRAY['Sit on the floor and spread your legs out comfortably.','Clean one kettlebell to your shoulder.','Press the kettlebell up and out until it is locked out overhead. Return to the starting position.'],'Sit on the floor and spread your legs out comfortably. Clean one kettlebell to your shoulder. Press the kettlebell up and out until it is locked out overhead. Return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Seated_Press/0.jpg','exercisedb',true),('Kettlebell_Seesaw_Press','Kettlebell Seesaw Press','hombros',ARRAY['tríceps'],'kettlebells','strength',ARRAY['Clean two kettlebells two your shoulders.','Press one kettlebell.','Lower the kettlebell and immediately press the other kettlebell. Make sure to do the same amount of reps on both sides.'],'Clean two kettlebells two your shoulders. Press one kettlebell. Lower the kettlebell and immediately press the other kettlebell. Make sure to do the same amount of reps on both sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Seesaw_Press/0.jpg','exercisedb',true),('Kettlebell_Sumo_High_Pull','Kettlebell Sumo High Pull','trapecios',ARRAY['aductores','glúteos','isquiotibiales','cuádriceps','hombros'],'kettlebells','strength',ARRAY['Place a kettlebell on the ground between your feet. Position your feet in a wide stance, and grasp the kettlebell with two hands. Set your hips back as far as possible, with your knees bent. Keep your chest and head up. This will be your starting position.','Begin by extending the hips and knees, simultaneously pulling the kettlebell to your shoulders, raising your elbows as you do so. Reverse the motion to return to the starting position.'],'Place a kettlebell on the ground between your feet. Position your feet in a wide stance, and grasp the kettlebell with two hands. Set your hips back as far as possible, with your knees bent. Keep your chest and head up. This will be your starting position. Begin by extending the hips and knees, simultaneously pulling the kettlebell to your shoulders, raising your elbows as you do so. Reverse the motion to return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Sumo_High_Pull/0.jpg','exercisedb',true),('Kettlebell_Thruster','Kettlebell Thruster','hombros',ARRAY['cuádriceps','tríceps'],'kettlebells','strength',ARRAY['Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so. This will be your starting position.','Begin to squat by flexing your hips and knees, lowering your hips between your legs. Maintain an upright, straight back as you descend as low as you can.','At the bottom, reverse direction and squat by extending your knees and hips, driving through your heels. As you do so, press both kettlebells overhead by extending your arms straight up, using the momentum from the squat to help drive the weights upward.','As you begin the next repetition, return the weights to the shoulders.'],'Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so. This will be your starting position. Begin to squat by flexing your hips and knees, lowering your hips between your legs. Maintain an upright, straight back as you descend as low as you can. At the bottom, reverse direction and squat by extending your knees and hips, driving through your heels. As you do so, press both kettlebells overhead by extending your arms straight up, using the momentum from the squat to help drive the weights upward. As you begin the next repetition, return the weights to the shoulders.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Thruster/0.jpg','exercisedb',true),('Kettlebell_Turkish_Get-Up_Lunge_style','Kettlebell Turkish Get-Up (Lunge style)','hombros',ARRAY['abdominales','isquiotibiales','cuádriceps','tríceps'],'kettlebells','strength',ARRAY['Lie on your back on the floor and press a kettlebell to the top position by extending the elbow. Bend the knee on the same side as the kettlebell.','Keeping the kettlebell locked out at all times, pivot to the opposite side and use your non- working arm to assist you in driving forward to the lunge position. Using your free hand, push yourself to a seated position, then progressing to one knee.','While looking up at the kettlebell, slowly stand up. Reverse the motion back to the starting position and repeat.'],'Lie on your back on the floor and press a kettlebell to the top position by extending the elbow. Bend the knee on the same side as the kettlebell. Keeping the kettlebell locked out at all times, pivot to the opposite side and use your non- working arm to assist you in driving forward to the lunge position. Using your free hand, push yourself to a seated position, then progressing to one knee. While looking up at the kettlebell, slowly stand up. Reverse the motion back to the starting position and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Turkish_Get-Up_Lunge_style/0.jpg','exercisedb',true),('Kettlebell_Turkish_Get-Up_Squat_style','Kettlebell Turkish Get-Up (Squat style)','hombros',ARRAY['abdominales','pantorrillas','isquiotibiales','cuádriceps','tríceps'],'kettlebells','strength',ARRAY['Lie on your back on the floor and press a kettlebell to the top position by extending the elbow. Bend the knee on the same side as the kettlebell.','Keeping the kettlebell locked out at all times, pivot to the opposite side and use your non- working arm to assist you in driving forward to the lunge position.','Using your free hand, push yourself to a seated position, then progressing to your feet. While looking up at the kettlebell, slowly stand up. Reverse the motion back to the starting position and repeat.'],'Lie on your back on the floor and press a kettlebell to the top position by extending the elbow. Bend the knee on the same side as the kettlebell. Keeping the kettlebell locked out at all times, pivot to the opposite side and use your non- working arm to assist you in driving forward to the lunge position. Using your free hand, push yourself to a seated position, then progressing to your feet. While looking up at the kettlebell, slowly stand up. Reverse the motion back to the starting position and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Turkish_Get-Up_Squat_style/0.jpg','exercisedb',true),('Kettlebell_Windmill','Kettlebell Windmill','abdominales',ARRAY['glúteos','isquiotibiales','hombros','tríceps'],'kettlebells','strength',ARRAY['Place a kettlebell in front of your lead foot and clean and press it overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward. Press it overhead by extending the elbow.','Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell. Bending at the hip to one side, sticking your butt out, slowly lean until you can touch the floor with your free hand. Keep your eyes on the kettlebell that you hold over your head at all times.','Pause for a second after reaching the ground and reverse the motion back to the starting position.'],'Place a kettlebell in front of your lead foot and clean and press it overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward. Press it overhead by extending the elbow. Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell. Bending at the hip to one side, sticking your butt out, slowly lean until you can touch the floor with your free hand. Keep your eyes on the kettlebell that you hold over your head at all times. Pause for a second after reaching the ground and reverse the motion back to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Windmill/0.jpg','exercisedb',true),('Kipping_Muscle_Up','Kipping Muscle Up','dorsales',ARRAY['abdominales','bíceps','antebrazos','espalda media','hombros','trapecios','tríceps'],'otro','strength',ARRAY['Grip the rings using a false grip, with the base of your palms on top of the rings.','Begin with a movement swinging your legs backward slightly.','Counter that movement by swinging your legs forward and up, jerking your chin and chest back, pulling yourself up with both arms as you do so. As you reach the top position of the pull-up, pull the rings to your armpits as you roll your shoulders forward, allowing your elbows to move straight back behind you. This puts you into the proper position to continue into the dip portion of the movement.','Maintaining control and stability, extend through the elbow to complete the motion.','Use care when lowering yourself to the ground.'],'Grip the rings using a false grip, with the base of your palms on top of the rings. Begin with a movement swinging your legs backward slightly. Counter that movement by swinging your legs forward and up, jerking your chin and chest back, pulling yourself up with both arms as you do so. As you reach the top position of the pull-up, pull the rings to your armpits as you roll your shoulders forward, allowing your elbows to move straight back behind you. This puts you into the proper position to continue into the dip portion of the movement. Maintaining control and stability, extend through the elbow to complete the motion. Use care when lowering yourself to the ground.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kipping_Muscle_Up/0.jpg','exercisedb',true),('Knee_Across_The_Body','Knee Across The Body','glúteos',ARRAY['abductores','espalda baja'],NULL,'stretching',ARRAY['Lie down on the floor with your right leg straight. Bend your left leg and lower it across your body, holding the knee down toward the floor with your right hand. (The knee doesn''''t need to touch the floor if you''''re tight.)','Place your left arm comfortably beside you and turn your head to the left. Imagine you have a weight tied to your tailbone. let your tailbone fall back toward the floor as your chest reaches in the opposite direction to stretch your lower back. Switch sides.'],'Lie down on the floor with your right leg straight. Bend your left leg and lower it across your body, holding the knee down toward the floor with your right hand. (The knee doesn''t need to touch the floor if you''re tight.) Place your left arm comfortably beside you and turn your head to the left. Imagine you have a weight tied to your tailbone. let your tailbone fall back toward the floor as your chest reaches in the opposite direction to stretch your lower back. Switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Across_The_Body/0.jpg','exercisedb',true),('Knee_Circles','Knee Circles','pantorrillas',ARRAY['isquiotibiales','cuádriceps'],'peso corporal','stretching',ARRAY['Stand with your legs together and hands by your waist.','Now move your knees in a circular motion as you breathe normally.','Repeat for the recommended amount of repetitions.'],'Stand with your legs together and hands by your waist. Now move your knees in a circular motion as you breathe normally. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Circles/0.jpg','exercisedb',true),('Knee_Hip_Raise_On_Parallel_Bars','Knee/Hip Raise On Parallel Bars','abdominales',ARRAY[],'otro','strength',ARRAY['Position your body on the vertical leg raise bench so that your forearms are resting on the pads next to the torso and holding on to the handles. Your arms will be bent at a 90 degree angle.','The torso should be straight with the lower back pressed against the pad of the machine and the legs extended pointing towards the floor. This will be your starting position.','Now as you breathe out, lift your legs up as you keep them extended. Continue this movement until your legs are roughly parallel to the floor and then hold the contraction for a second. Tip: Do not use any momentum or swinging as you perform this exercise.','Slowly go back to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'],'Position your body on the vertical leg raise bench so that your forearms are resting on the pads next to the torso and holding on to the handles. Your arms will be bent at a 90 degree angle. The torso should be straight with the lower back pressed against the pad of the machine and the legs extended pointing towards the floor. This will be your starting position. Now as you breathe out, lift your legs up as you keep them extended. Continue this movement until your legs are roughly parallel to the floor and then hold the contraction for a second. Tip: Do not use any momentum or swinging as you perform this exercise. Slowly go back to the starting position as you breathe in. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Hip_Raise_On_Parallel_Bars/0.jpg','exercisedb',true),('Knee_Tuck_Jump','Knee Tuck Jump','isquiotibiales',ARRAY['abductores','aductores','pantorrillas','glúteos','cuádriceps'],'peso corporal','plyometrics',ARRAY['Begin in a comfortable standing position with your knees slightly bent. Hold your hands in front of you, palms down with your fingertips together at chest height. This will be your starting position.','Rapidly dip down into a quarter squat and immediately explode upward. Drive the knees towards the chest, attempting to touch them to the palms of the hands.','Jump as high as you can, raising your knees up, and then ensure a good land be re-extending your legs, absorbing impact through be allowing the knees to rebend.'],'Begin in a comfortable standing position with your knees slightly bent. Hold your hands in front of you, palms down with your fingertips together at chest height. This will be your starting position. Rapidly dip down into a quarter squat and immediately explode upward. Drive the knees towards the chest, attempting to touch them to the palms of the hands. Jump as high as you can, raising your knees up, and then ensure a good land be re-extending your legs, absorbing impact through be allowing the knees to rebend.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Tuck_Jump/0.jpg','exercisedb',true),('Kneeling_Arm_Drill','Kneeling Arm Drill','hombros',ARRAY['abdominales'],NULL,'plyometrics',ARRAY['This drill helps increase arm efficiency during the run. Begin kneeling, left foot in front, right knee down. Apply pressure through the front heel to keep your glutes and hamstrings activated.','Begin by blocking the arms in long, pendulum like swings. Close the arm angle, blocking with the arms as you would when jogging, progressing to a run and finally a sprint.','As soon as your hands pass the hip, accelerate them forward during the sprinting motion to move them as quickly as possible.','Switch knees and repeat.'],'This drill helps increase arm efficiency during the run. Begin kneeling, left foot in front, right knee down. Apply pressure through the front heel to keep your glutes and hamstrings activated. Begin by blocking the arms in long, pendulum like swings. Close the arm angle, blocking with the arms as you would when jogging, progressing to a run and finally a sprint. As soon as your hands pass the hip, accelerate them forward during the sprinting motion to move them as quickly as possible. Switch knees and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Arm_Drill/0.jpg','exercisedb',true),('Kneeling_Cable_Crunch_With_Alternating_Oblique_Twists','Kneeling Cable Crunch With Alternating Oblique Twists','abdominales',ARRAY[],'cable','strength',ARRAY['Connect a rope attachment to a high pulley cable and position a mat on the floor in front of it.','Grab the rope with both hands and kneel approximately two feet back from the tower.','Position the rope behind your head with your hands by your ears.','Keep your hands in the same place, contract your abs and pull downward on the rope in a crunching movement until your elbows reach your knees.','Pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position.','Repeat the same downward movement until you''''re halfway down, at which time you''''ll begin rotating one of your elbows to the opposite knee.','Again, pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position.','Repeat the same movement as before, but alternate the other elbow to the opposite knee.','Continue this series of movements to failure.'],'Connect a rope attachment to a high pulley cable and position a mat on the floor in front of it. Grab the rope with both hands and kneel approximately two feet back from the tower. Position the rope behind your head with your hands by your ears. Keep your hands in the same place, contract your abs and pull downward on the rope in a crunching movement until your elbows reach your knees. Pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position. Repeat the same downward movement until you''re halfway down, at which time you''ll begin rotating one of your elbows to the opposite knee. Again, pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position. Repeat the same movement as before, but alternate the other elbow to the opposite knee. Continue this series of movements to failure.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Crunch_With_Alternating_Oblique_Twists/0.jpg','exercisedb',true),('Kneeling_Cable_Triceps_Extension','Kneeling Cable Triceps Extension','tríceps',ARRAY[],'cable','strength',ARRAY['Place a bench sideways in front of a high pulley machine.','Hold a straight bar attachment above your head with your hands about 6 inches apart with your palms facing down.','Face away from the machine and kneel.','Place your head and the back of your upper arms on the bench. Your elbows should be bent with the forearms pointing towards the high pulley. This will be your starting position.','While keeping your upper arms close to your head at all times with the elbows in, press the bar out in a semicircular motion until the elbows are locked and your arms are parallel to the floor. Contract the triceps hard and keep this position for a second. Exhale as you perform this movement.','Slowly return to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'],'Place a bench sideways in front of a high pulley machine. Hold a straight bar attachment above your head with your hands about 6 inches apart with your palms facing down. Face away from the machine and kneel. Place your head and the back of your upper arms on the bench. Your elbows should be bent with the forearms pointing towards the high pulley. This will be your starting position. While keeping your upper arms close to your head at all times with the elbows in, press the bar out in a semicircular motion until the elbows are locked and your arms are parallel to the floor. Contract the triceps hard and keep this position for a second. Exhale as you perform this movement. Slowly return to the starting position as you breathe in. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Triceps_Extension/0.jpg','exercisedb',true),('Kneeling_Forearm_Stretch','Kneeling Forearm Stretch','antebrazos',ARRAY[],NULL,'stretching',ARRAY['Start by kneeling on a mat with your palms flat and your fingers pointing back toward your knees.','Slowly lean back keeping your palms flat on the floor until you feel a stretch in your wrists and forearms. Hold for 20-30 seconds.'],'Start by kneeling on a mat with your palms flat and your fingers pointing back toward your knees. Slowly lean back keeping your palms flat on the floor until you feel a stretch in your wrists and forearms. Hold for 20-30 seconds.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Forearm_Stretch/0.jpg','exercisedb',true),('Kneeling_High_Pulley_Row','Kneeling High Pulley Row','dorsales',ARRAY['bíceps','espalda media'],'cable','strength',ARRAY['Select the appropriate weight using a pulley that is above your head. Attach a rope to the cable and kneel a couple of feet away, holding the rope out in front of you with both arms extended. This will be your starting position.','Initiate the movement by flexing the elbows and fully retracting your shoulders, pulling the rope toward your upper chest with your elbows out.','After pausing briefly, slowly return to the starting position.'],'Select the appropriate weight using a pulley that is above your head. Attach a rope to the cable and kneel a couple of feet away, holding the rope out in front of you with both arms extended. This will be your starting position. Initiate the movement by flexing the elbows and fully retracting your shoulders, pulling the rope toward your upper chest with your elbows out. After pausing briefly, slowly return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_High_Pulley_Row/0.jpg','exercisedb',true),('Kneeling_Hip_Flexor','Kneeling Hip Flexor','cuádriceps',ARRAY['cuádriceps'],NULL,'stretching',ARRAY['Kneel on a mat and bring your right knee up so the bottom of your foot is on the floor and extend your left leg out behind you so the top of your foot is on the floor.','Shift your weight forward until you feel a stretch in your hip. Hold for 15 seconds, then repeat for your other side.'],'Kneel on a mat and bring your right knee up so the bottom of your foot is on the floor and extend your left leg out behind you so the top of your foot is on the floor. Shift your weight forward until you feel a stretch in your hip. Hold for 15 seconds, then repeat for your other side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Hip_Flexor/0.jpg','exercisedb',true),('Kneeling_Jump_Squat','Kneeling Jump Squat','glúteos',ARRAY['pantorrillas','isquiotibiales','cuádriceps'],'barra','olympic weightlifting',ARRAY['Begin kneeling on the floor with a barbell racked across the back of your shoulders, or you can use your body weight for this exercise. This can be done inside of a power rack to make unracking easier.','Sit back with your hips until your glutes touch your feet, keeping your head and chest up.','Explode up with your hips, generating enough power to land with your feet flat on the floor.','Continue with the squat by driving through your heels and extending the knees to come to a standing position.'],'Begin kneeling on the floor with a barbell racked across the back of your shoulders, or you can use your body weight for this exercise. This can be done inside of a power rack to make unracking easier. Sit back with your hips until your glutes touch your feet, keeping your head and chest up. Explode up with your hips, generating enough power to land with your feet flat on the floor. Continue with the squat by driving through your heels and extending the knees to come to a standing position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Jump_Squat/0.jpg','exercisedb',true),('Kneeling_Single-Arm_High_Pulley_Row','Kneeling Single-Arm High Pulley Row','dorsales',ARRAY['bíceps','espalda media'],'cable','strength',ARRAY['Attach a single handle to a high pulley and make your weight selection.','Kneel in front of the cable tower, taking the cable with one hand with your arm extended. This will be your starting position.','Starting with your palm facing forward, pull the weight down to your torso by flexing the elbow and retract the shoulder blade. As you do so, rotate the wrist so that at the completion of the movement, your palm is now facing you.','After a brief pause, return to the starting position.'],'Attach a single handle to a high pulley and make your weight selection. Kneel in front of the cable tower, taking the cable with one hand with your arm extended. This will be your starting position. Starting with your palm facing forward, pull the weight down to your torso by flexing the elbow and retract the shoulder blade. As you do so, rotate the wrist so that at the completion of the movement, your palm is now facing you. After a brief pause, return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Single-Arm_High_Pulley_Row/0.jpg','exercisedb',true),('Kneeling_Squat','Kneeling Squat','glúteos',ARRAY['abdominales','isquiotibiales','espalda baja'],'barra','powerlifting',ARRAY['Set the bar to the proper height in a power rack. Kneel behind the bar; it may be beneficial to put a mat down to pad your knees. Slide under the bar, racking it across the back of your shoulders. Your shoulder blades should be retracted and the bar tight across your back. Unrack the weight.','With your head looking forward, sit back with your butt until you touch your calves.','Reverse the motion, returning the torso to an upright position.'],'Set the bar to the proper height in a power rack. Kneel behind the bar; it may be beneficial to put a mat down to pad your knees. Slide under the bar, racking it across the back of your shoulders. Your shoulder blades should be retracted and the bar tight across your back. Unrack the weight. With your head looking forward, sit back with your butt until you touch your calves. Reverse the motion, returning the torso to an upright position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Squat/0.jpg','exercisedb',true);